def format_result(keyed_window_output) -> str:
    """
    Convert ``(service, (WindowMetadata, ApdexAccumulator))`` into a JSON line.
    """
    service, (meta, acc) = keyed_window_output
    window_start = meta.open_time.strftime("%Y-%m-%dT%H:%M:%SZ")
    result = {
        "window_start": window_start,
        "service": service,
        "apdex_score": round(acc.score, 2),
    }
    return json.dumps(result)

